{{
(async () => {

  // 1. Nie można dezaktywować własnego konta
  if (
    appsmith.store.editUser.id ===
    appsmith.store.session.user.id
  ) {

    showAlert(
      "Nie można dezaktywować aktualnie zalogowanego użytkownika.",
      "warning"
    );

    return;
  }

  // 2. Jeżeli usuwamy administratora,
  // sprawdzamy czy nie jest ostatnim administratorem
  if (appsmith.store.editUser.role_code === "ADMIN") {

    await countAdmins.run();

    if (
      Number(countAdmins.data[0].admin_count) <= 1
    ) {

      showAlert(
        "W systemie musi pozostać co najmniej jeden administrator.",
        "warning"
      );

      return;
    }

  }

  // 3. Dezaktywacja użytkownika
  deleteUser.run(

    () => {

      getUsers.run(

        () => {

          closeModal("ModalUsunUzytkownika");

          storeValue("editUser", null);

          showAlert(
            "Użytkownik został dezaktywowany.",
            "success"
          );

        },

        (error) => {

          showAlert(
            "Nie udało się odświeżyć listy użytkowników.",
            "warning"
          );

          console.error(error);

        }

      );

    },

    (error) => {

      showAlert(
        "Błąd podczas dezaktywacji użytkownika.",
        "error"
      );

      console.error(error);

    }

  );

})();
}}
